import{_ as e,o as a,c as r,ag as n}from"./chunks/framework.eQLvDOR_.js";const _=JSON.parse('{"title":"shared-state-pattern","description":"","frontmatter":{"title":"shared-state-pattern","concept":"共享状态模式","concept_id":"shared-state-pattern","aliases":[],"sources":["02_Library/Agent_Architecture/[Agent_Architecture] Multi-agent coordination patterns_ Five approaches and when to use them.md"],"related_concepts":["[[context-optimization]]"],"created_at":"2026-04-18","last_compiled":"2026-04-18"},"headers":[],"relativePath":"wiki/concepts/shared-state-pattern.md","filePath":"wiki/concepts/shared-state-pattern.md","lastUpdated":null}'),i={name:"wiki/concepts/shared-state-pattern.md"};function o(s,t,c,h,l,d){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="共享状态模式-shared-state-pattern" tabindex="-1">共享状态模式 (Shared-state Pattern) <a class="header-anchor" href="#共享状态模式-shared-state-pattern" aria-label="Permalink to &quot;共享状态模式 (Shared-state Pattern)&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>所有 Agent 在执行过程中共享同一个内存空间或外部数据库，并能感知彼此对该空间的写入和标记，通过对同一实体状态的并发探索达成任务。</p><h2 id="核心要点" tabindex="-1">核心要点 <a class="header-anchor" href="#核心要点" aria-label="Permalink to &quot;核心要点&quot;">​</a></h2><ul><li><strong>群体智能涌现</strong>：通过黑板架构（Blackboard System），不需要直接对话（避免大量无效消息），也能实现不同 Agent 接力处理同一个复杂目标（如共同写一本书的不同章节或寻找漏洞群）。（来源：<a href="/s/webclips/library/Agent_Architecture/Agent_Architecture - Multi-agent coordination patterns_ Five approaches and when to use them.html">[Agent_Architecture] Multi-agent coordination patterns_ Five approaches and when to use them.md</a>）</li><li><strong>状态锁</strong>：非常依赖底层平台对于共享节点的正确排他锁设定，否则易引发状态冲突。</li></ul><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><p>如果两个智能体需要进行复杂的资料共享，放弃让它们互发长篇消息，转而让它们读写同一个共享状态持久化文件（如 JSON）。</p><h2 id="关联概念" tabindex="-1">关联概念 <a class="header-anchor" href="#关联概念" aria-label="Permalink to &quot;关联概念&quot;">​</a></h2><ul><li><a href="/s/webclips/wiki/concepts/context-optimization.html">context-optimization</a> — 这是将 Token 从上下文对话框剥离到持久层的重要实现方式。</li></ul>',9)])])}const u=e(i,[["render",o]]);export{_ as __pageData,u as default};
